#include <bits/stdc++.h>
using namespace std;

void solve() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<int> V(n);

        for (int i = 0; i < n; i++) {
            cin >> V[i];
        }

        sort(V.begin(), V.end(), greater<int>());

        int max1 = 0, max2 = 0;
        int i = 0;

        // Find first pair
        while (i < n - 1) {
            if (V[i] == V[i + 1]) {
                max1 = V[i];
                i += 2;
                break;
            }
            i++;
        }

        // Find second pair
        while (i < n - 1) {
            if (V[i] == V[i + 1]) {
                max2 = V[i];
                i += 2;
                break;
            }
            i++;
        }

        if (max1 > 0 && max2 > 0) {
            cout << max1 * max2 << endl;
        } else {
            cout << -1 << endl;
        }
    }
}

int main() {
    solve();
    return 0;
}

