function Sticks(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]);

    let index = 1;
    for (let t = 0; t < T; t++) {
        const n = parseInt(lines[index++]);
        const V = lines[index++].split(' ').map(Number);

        let flag = false;
        V.sort((a, b) => b - a); // Sort the sticks in descending order

        let max1 = 0;
        let max2 = 0;
        let idx = -1;

        for (let i = 0; i < n - 1; i++) {
            if (V[i] === V[i + 1]) {
                idx = i;
                max1 = V[i];
                flag = true;
                break;
            } else {
                flag = false;
            }
        }

        for (let i = 0; i < n - 1; i++) {
            if (V[i] === V[i + 1] && i !== idx && i !== idx + 1) {
                max2 = V[i];
                flag = true;
                break;
            } else {
                flag = false;
            }
        }

        if (flag) {
            console.log(max1 * max2);
        } else {
            console.log(-1);
        }
    }
}

